// ============================================
// AGENTE TÉCNICO - Versión Final Optimizada
// ============================================

const context = $input.all()[0].json;
const marketData = context.market_data;

const technicalData = {
    symbol: marketData.best_pair || "EURUSD",
    price: marketData.technical?.current_price || 0,
    rsi: marketData.technical?.rsi || 50,
    trend: marketData.technical?.trend || "neutral",
    support: marketData.technical?.support || 0,
    resistance: marketData.technical?.resistance || 0,
    score: marketData.best_score || 0
};

const rsiStatus = technicalData.rsi < 30 ? "oversold" : (technicalData.rsi > 70 ? "overbought" : "neutral");
const rangeLow = (technicalData.price - 0.001).toFixed(5);
const rangeHigh = (technicalData.price + 0.001).toFixed(5);
const stopLow = (technicalData.price - 0.003).toFixed(5);
const stopHigh = (technicalData.price - 0.002).toFixed(5);

// Prompt optimizado (~180 tokens)
const prompt = `[INST] Tech analysis ${technicalData.symbol}. P:${technicalData.price} RSI:${technicalData.rsi}(${rsiStatus}) Tr:${technicalData.trend} Sup:${technicalData.support} Res:${technicalData.resistance}. Return JSON: signal(buy/sell/neutral), confidence(0-100), analysis, structure(bullish/bearish/range), momentum(strong/moderate/weak), entry_zone[${rangeLow},${rangeHigh}], stop_zone[${stopLow},${stopHigh}] [/INST]`;

console.log("📈 Agente Técnico - Prompt length:", prompt.length);
console.log(`   RSI: ${technicalData.rsi} (${rsiStatus})`);
console.log(`   Entry zone: ${rangeLow} - ${rangeHigh}`);

return [{
    json: {
        agent: "technical",
        context: context,
        technical_data: technicalData,
        prompt: prompt,
        status: "ready"
    }
}];

// ============================================
// AGENTE FUNDAMENTAL - Versión Máximamente Optimizada
// ============================================

const context = $input.all()[0].json;
const marketData = context.market_data;

const fd = {
    s: marketData.best_pair || "EURUSD",
    n: marketData.fundamental?.news_count || 0,
    hi: marketData.fundamental?.high_impact_events || 0
};

// Determinar riesgo e impacto
let risk = "low";
let dir = "neutral";
if (fd.hi > 2) { risk = "high"; dir = "volatile"; }
else if (fd.hi > 0) risk = "medium";

// Prompt ultra corto (~100 tokens)
const prompt = `[INST] Fundamental ${fd.s}. N:${fd.n} HI:${fd.hi} R:${risk}. Return JSON: recommendation(act/wait/avoid), confidence(0-100), analysis, impact_direction(bullish/bearish/neutral/volatile), sentiment_score(-100 to 100) [/INST]`;

console.log("📰 Agente Fundamental - Prompt length:", prompt.length);

return [{
    json: {
        agent: "fundamental",
        context: context,
        fundamental_data: fd,
        prompt: prompt,
        status: "ready"
    }
}];

// ============================================
// AGENTE SENTIMIENTO - Versión Máximamente Optimizada
// ============================================

const context = $input.all()[0].json;
const marketData = context.market_data;

// Datos de posiciones
const pos = marketData.positions?.details || [];
let long = 0, short = 0;
for (const p of pos) {
    const v = Math.abs(p.volume || 0);
    if (p.type === "buy" || p.type === "long" || p.type === "BUY") long += v;
    else if (p.type === "sell" || p.type === "short" || p.type === "SELL") short += v;
}

// Datos de pendientes
const pend = marketData.pending_orders?.details || [];
let plong = 0, pshort = 0;
for (const p of pend) {
    const v = Math.abs(p.volume || 0);
    if (p.type && (p.type.includes("BUY") || p.type === "buy")) plong += v;
    if (p.type && (p.type.includes("SELL") || p.type === "sell")) pshort += v;
}

// Ratio combinado
const totalLong = long + plong;
const totalShort = short + pshort;
const total = totalLong + totalShort;
let ratio = 0;
if (total > 0) ratio = ((totalLong - totalShort) / total) * 100;

// Señal contraria
let cs = "none";
if (ratio > 60) cs = "sell";
else if (ratio < -60) cs = "buy";

// Prompt ultra corto (~100 tokens)
const prompt = `[INST] Sentiment ${marketData.best_pair || "EURUSD"}. L:${totalLong.toFixed(1)} S:${totalShort.toFixed(1)} R:${ratio.toFixed(0)}. Return JSON: sentiment(bullish/bearish/neutral), confidence(0-100), analysis, contrary_signal(buy/sell/none), sentiment_score(-100 to 100) [/INST]`;

console.log(`💭 Sentimiento - L:${totalLong.toFixed(1)} S:${totalShort.toFixed(1)} R:${ratio.toFixed(0)}% CS:${cs}`);

return [{
    json: {
        agent: "sentiment",
        context: context,
        prompt: prompt,
        status: "ready"
    }
}];

// ============================================
// AGENTE ESTADÍSTICO - Versión Máximamente Optimizada
// ============================================

const context = $input.all()[0].json;
const marketData = context.market_data;
const mem = context.memory || {};
const gm = mem.global_metrics || {};

const sd = {
    s: marketData.best_pair || "EURUSD",
    p: marketData.technical?.current_price || 0,
    r: marketData.technical?.rsi || 50,
    t: marketData.technical?.trend || "neutral",
    sc: marketData.best_score || 0
};

const wr = gm.winrate || 0;
const tt = gm.total_trades || 0;

// Prompt ultra corto (~60-80 tokens)
const prompt = `[INST] Stats ${sd.s}. R:${sd.r} T:${sd.t} Sc:${sd.sc} WR:${wr.toFixed(0)}% Tr:${tt}. Return JSON: volatility, volume_adjustment, probability, confidence [/INST]`;

console.log("📊 Agente Estadístico - Prompt length:", prompt.length);

return [{
    json: {
        agent: "statistical",
        context: context,
        statistical_data: sd,
        prompt: prompt,
        status: "ready"
    }
}];

