// ============================================
// AGENTE ESTRATEGA - Versión Corregida
// ============================================

const allAgents = $input.all();

// Inicializar con valores por defecto seguros
let technical = { s: "neutral", c: 0 };
let fundamental = { r: "wait", c: 0, d: "neutral" };
let sentiment = { s: "neutral", c: 0, cs: "none" };
let statistical = { c: 0 };
let marketData = {};
let agentWeights = { t: 0.35, f: 0.25, se: 0.25, st: 0.15 };

// Extraer datos de agentes
for (const item of allAgents) {
    const data = item.json;
    const a = data.analysis;

    if (data.agent === "technical" && a) {
        technical = { 
            s: a.señal || a.signal || "neutral", 
            c: typeof a.confianza === 'number' ? a.confianza : 0 
        };
    }
    if (data.agent === "fundamental" && a) {
        fundamental = { 
            r: a.recomendacion || a.recommendation || "wait", 
            c: typeof a.confianza === 'number' ? a.confianza : 0,
            d: a.direccion_impacto || a.impact_direction || "neutral" 
        };
    }
    if (data.agent === "sentiment" && a) {
        sentiment = { 
            s: a.sentimiento || a.sentiment || "neutral", 
            c: typeof a.confianza === 'number' ? a.confianza : 0,
            cs: a.señal_contraria || a.contrary_signal || "none" 
        };
    }
    if (data.agent === "statistical" && a) {
        statistical = { c: typeof a.confianza === 'number' ? a.confianza : 0 };
    }
    if (data.context) {
        marketData = data.context.market_data || {};
        if (data.context.memory?.agent_weights) {
            agentWeights = data.context.memory.agent_weights;
        }
    }
}

const price = marketData.technical?.current_price || 0;
const accountBalance = marketData.risk?.account_balance || 100000;

// Calcular score con validación
const tScore = (technical.c / 100) * (agentWeights.t || 0.35);
const fScore = (fundamental.c / 100) * (agentWeights.f || 0.25);
const seScore = (sentiment.c / 100) * (agentWeights.se || 0.25);
const stScore = (statistical.c / 100) * (agentWeights.st || 0.15);
const totalScore = (tScore + fScore + seScore + stScore) * 100;

// Asegurar que no sea NaN
const finalScore = isNaN(totalScore) ? 0 : Math.min(100, Math.max(0, totalScore));

// Contar señales (usando inglés consistentemente)
let buy = 0, sell = 0;
if (technical.s === "buy") buy++;
if (technical.s === "sell") sell++;
if (fundamental.r === "act" && fundamental.d === "bullish") buy++;
if (fundamental.r === "act" && fundamental.d === "bearish") sell++;
if (sentiment.cs === "buy") buy++;
if (sentiment.cs === "sell") sell++;

// Decisión
let decision = "hold";
if (finalScore >= 45 && buy > sell && buy >= 1) decision = "buy";
else if (finalScore >= 45 && sell > buy && sell >= 1) decision = "sell";

// ============================================
// CÁLCULO DE VOLUMEN SEGURO
// ============================================

const stopLossPips = 50;
const pipValue = 10;
const riskPercent = 0.02;
const maxRiskAmount = accountBalance * riskPercent;
const calculatedVolume = maxRiskAmount / (stopLossPips * pipValue);
const MAX_VOLUME = 0.25;
const MIN_VOLUME = 0.01;

let volume = Math.min(calculatedVolume, MAX_VOLUME);
volume = Math.max(volume, MIN_VOLUME);
volume = Math.round(volume * 100) / 100;

console.log(`💰 Volumen: ${volume} lotes | Riesgo: $${(volume * stopLossPips * pipValue).toFixed(2)} (${((volume * stopLossPips * pipValue) / accountBalance * 100).toFixed(2)}%)`);

// Niveles de stop y take profit
let sl = 0, tp1 = 0, tp2 = 0;
if (decision === "buy") {
    sl = Math.round((price - 0.003) * 100000) / 100000;
    tp1 = Math.round((price + 0.003) * 100000) / 100000;
    tp2 = Math.round((price + 0.005) * 100000) / 100000;
} else if (decision === "sell") {
    sl = Math.round((price + 0.003) * 100000) / 100000;
    tp1 = Math.round((price - 0.003) * 100000) / 100000;
    tp2 = Math.round((price - 0.005) * 100000) / 100000;
}

// Prompt simplificado
const prompt = `[INST] T:${technical.s}(${technical.c}%) F:${fundamental.r}(${fundamental.c}%) Se:${sentiment.s}(${sentiment.c}%) St:${statistical.c}% P:${price} B:${accountBalance} Bs:${buy} Ss:${sell} Sc:${Math.round(finalScore)}. Return JSON: decision(buy/sell/hold), confidence(0-100), reasoning, entry_price, stop_loss, take_profit, volume [/INST]`;

console.log(`🎯 Decisión: ${decision}, Score: ${finalScore}%, Buy:${buy} Sell:${sell}`);

return [{
    json: {
        decision: decision,
        confianza: finalScore,
        razonamiento: `T:${technical.c}% F:${fundamental.c}% Se:${sentiment.c}% St:${statistical.c}%`,
        entrada: { precio: price, tolerancia: 0.0005 },
        stop_loss: { precio: sl, pips: 30 },
        take_profit: { objetivo1: tp1, objetivo2: tp2 },
        volumen: volume,
        prompt: prompt
    }
}];

