// Nodo: "Parse Estratega"
const response = $json.choices[0].text.trim();
const strategistData = $node["Agente Estratega"].json;

console.log("Respuesta raw:", response);

try {
    // Buscar JSON en la respuesta (puede estar en markdown o texto plano)
    let jsonMatch = null;

    // Buscar JSON dentro de bloque de código ```json ... ```
    const codeBlockMatch = response.match(/```json\s*([\s\S]*?)\s*```/);
    if (codeBlockMatch) {
        jsonMatch = codeBlockMatch[1];
    }

    // Si no, buscar cualquier {...}
    if (!jsonMatch) {
        const braceMatch = response.match(/\{[\s\S]*\}/);
        if (braceMatch) {
            jsonMatch = braceMatch[0];
        }
    }

    let decisionFromAI = null;
    if (jsonMatch) {
        try {
            // Limpiar el JSON antes de parsear
            let cleanJson = jsonMatch
                .replace(/,\s*}/g, '}')
                .replace(/,\s*]/g, ']')
                .replace(/(['"])?([a-zA-Z0-9_]+)(['"])?\s*:/g, '"$2":');
            decisionFromAI = JSON.parse(cleanJson);
            console.log("✅ JSON parseado:", decisionFromAI);
        } catch(e) {
            console.log("Error parseando JSON:", e.message);
        }
    }

    // Combinar: priorizar AI, fallback a local
    const finalDecision = {
        decision: decisionFromAI?.decision || strategistData.decision,
        confianza: decisionFromAI?.confidence || strategistData.confianza,
        razonamiento: decisionFromAI?.reasoning || strategistData.razonamiento,
        entrada: strategistData.entrada,
        stop_loss: strategistData.stop_loss,
        take_profit: strategistData.take_profit,
        volumen: decisionFromAI?.volume || strategistData.volumen
    };

    console.log("🎯 Decisión final:", finalDecision.decision, "confianza:", finalDecision.confianza);

    return [{ json: finalDecision }];

} catch (error) {
    console.error("Error en Parse Estratega:", error.message);
    return [{
        json: {
            decision: strategistData.decision,
            confianza: strategistData.confianza,
            razonamiento: strategistData.razonamiento,
            entrada: strategistData.entrada,
            stop_loss: strategistData.stop_loss,
            take_profit: strategistData.take_profit,
            volumen: strategistData.volumen
        }
    }];
}
